class Solution:
    def findMaxConsecutiveOnes(self, nums):
        best = 0
        n = len(nums)
        for i in range(n):
            if nums[i] == 1:
                j = i
                cnt = 0
                while j < n and nums[j] == 1:
                    cnt += 1
                    j += 1
                if cnt > best:
                    best = cnt
        return best

solutions.python:
class Solution:
    def findMaxConsecutiveOnes(self, nums):
        best = cur = 0
        for x in nums:
            if x == 1:
                cur += 1
                if cur > best:
                    best = cur
            else:
                cur = 0
        return best

