var findMaxConsecutiveOnes = function(nums) {
    let best = 0, cur = 0;
    for (const x of nums) {
        if (x === 1) {
            cur++;
            if (cur > best) best = cur;
        } else {
            cur = 0;
        }
    }
    return best;
